import sys, json
for line in sys.stdin:
  line=line.strip()
  if not line: continue
  msg=json.loads(line)
  mid=msg.get('id')
  method=msg.get('method')
  if method=='initialize':
    print(json.dumps({'jsonrpc':'2.0','id':mid,'result':{'protocolVersion':'2024-11-05','capabilities':{}}}), flush=True)
  elif method=='tools/list':
    print(json.dumps({'jsonrpc':'2.0','id':mid,'result':{'tools':[{'name':'read_file','description':'Read file content','inputSchema':{'type':'object'}},{'name':'write_file','description':'Write file content','inputSchema':{'type':'object'}}]}}), flush=True)
  elif method=='tools/call':
    print(json.dumps({'jsonrpc':'2.0','id':mid,'result':{'content':[{'type':'text','text':'file operation ok'}]}}), flush=True)

